public:
    bool hasCircularReference(vector<int>& head) {
        if (head == nullptr || head[0] < 0 || head[0] >= n) return true;
        int slow = head[0];
        int fast = head[0];
        while (slow != fast) {
            slow = head[slow];
            fast = head[fast];
            if (fast == -1 || fast >= n) return true;
        }
        return false;
    }
};

