#include <iostream>
#include <vector>
using namespace std;

int main() {
    int n;
    cin >> n;
    vector<int> head(n);
    for (int i = 0; i < n; i++) {
        cin >> head[i];
    }
    # test code

    bool has_reference = true;
    vector<bool> visited(n);
    for (int i = 0; i < n; i++) {
        if (visited[i]) {
            has_reference = false;
            break;
        }
        visited[i] = true;
        int node = head[i];
        while (node != -1) {
            if (visited[node]) {
                has_reference = false;
                break;
            }
            visited[node] = true;
            node = head[node];
        }
        if (!has_reference) break;
    }
    if (has_reference) {
        cout << "True";
    } else {
        cout << "False";
    }
    return 0;
}
